import functions from './functions.js';
// component
import Header from './component/header/Header.js';

function App() {
  const [user, setUser] = useState(null);


  useEffect(() => {
    const { test } = functions();
    const func = async () => {
      const data = await  test();
      console.log(data);
      return data.data.id;
    }
    setUser(func());
  }, []);

  return (
    <div className={style.main}>
      <BrowserRouter>
        <Header user={user}/>
        <Routes>

        </Routes>
      </BrowserRouter>
    </div>
  );
}

export default App;
